UPDATE STOCIVAP SET
      AP_USER_ID = #{PAY_USER_ID}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD     = #{ses.gateCd}
  AND AP_NUM      = #{AP_NUM}

UPDATE STOCIVPC SET
      AP_USER_ID = #{PAY_USER_ID}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD     = #{ses.gateCd}
  AND BUYER_CD    = #{BUYER_CD}
  AND INV_NUM     = #{INV_NUM}
  AND PAY_CNT     = #{PAY_CNT}
  AND PY_BUYER_CD = #{PY_BUYER_CD}
  AND PY_DEPT_CD  = #{PY_DEPT_CD}

UPDATE STOCPOPC
   SET PY_USER_ID = #{PAY_USER_ID}
WHERE GATE_CD     = #{ses.gateCd}
  AND BUYER_CD    = #{BUYER_CD}
  AND PO_NUM      = #{PO_NUM}
  AND PAY_CNT     = #{PAY_CNT}
  AND PY_BUYER_CD = #{PY_BUYER_CD}
  AND PY_DEPT_CD  = #{PY_DEPT_CD}

UPDATE STOCIVAP SET
      AP_AMT      = #{AP_AMT}
    , AP_DATE     = #{AP_DATE}
    , AP_ACCOUT   = #{AP_ACCOUT}
    , SIGN_STATUS = #{SIGN_STATUS}
    , MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND AP_NUM   = #{AP_NUM}

UPDATE STOCPODT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = #{PROGRESS_CD}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND PO_NUM   = #{PO_NUM}
  AND PO_SQ    = #{PO_SQ}

UPDATE STOCPRDT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = #{PROGRESS_CD}
WHERE GATE_CD  = #{ses.gateCd}
  AND (BUYER_CD, PR_NUM, PR_SQ) IN (
  			SELECT PB_BUYER_CD, PR_NUM, PR_SQ
  			  FROM STOCPODT
  			 WHERE GATE_CD  = #{ses.gateCd}
  			   AND BUYER_CD = #{BUYER_CD}
  			   AND PO_NUM   = #{PO_NUM}
  			   AND PO_SQ    = #{PO_SQ}
  	  )
  AND DEL_FLAG = '0'

mapper.select:
SELECT IVAP.AP_NUM , IVAP.INV_NUM , IVHD.VENDOR_CD AS VENDOR_CD ,GETCOMPANYNAME(POHD.GATE_CD, POHD.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM ,IVAP.VENDOR_USER_NM AS VENDOR_USER_NM ,IVAP.VENDOR_TEL_NUM AS VENDOR_TEL_NUM ,IVAP.VENDOR_CELL_NUM AS VENDOR_CELL_NUM , IVHD.CUR AS CUR , IVHD.VAT_TYPE AS VAT_TYPE ,(POHD.PO_CREATE_DATE, 'YYYY-MM-DD') AS PO_CREATE_DATE , POHD.PO_NUM AS PO_NUM , POHD.CTRL_USER_ID AS CTRL_USER_ID ,GETUSERNAME(POHD.GATE_CD, POHD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , POHD.INSPECT_USER_ID AS INSPECT_USER_ID ,GETUSERNAME(POHD.GATE_CD, POHD.INSPECT_USER_ID, #{ses.langCd}) AS INSPECT_USER_NM , IVPC.PAY_TERMS AS PAY_TERMS , POHD.PO_AMT AS PO_AMT , IVHD.BUYER_CD AS BUYER_CD , IVHD.DEPT_CD , POPY.PAY_CNT AS PAY_CNT , POPY.PAY_CNT_NM AS PAY_CNT_NM , POPY.PAY_PERCENT AS PAY_PERCENT , IVPC.AP_REQ_AMT AS PAY_AMT , IVHD.INV_AMT , CASE WHEN POHD.VAT_TYPE = '1' THEN TRUNC(IVPC.AP_REQ_AMT / 11) ELSE 0 END AS VAT_AMT , IVAP.VENDOR_RMK AS RMK_TEXT_NUM , IVAP.VENDOR_ATT_FILE_NUM AS ATT_FILE_NUM , IVHD.ATT_FILE_NUM2 AS C_ATT_FILE_NUM , IVHD.DELIVERY_TYPE , IVPC.PY_BUYER_CD ,GETCOMPANYNAME(IVPC.GATE_CD, IVPC.PY_BUYER_CD, #{ses.langCd}) AS PY_BUYER_NM , IVPC.PY_DEPT_CD ,GETDEPTNAME(IVPC.GATE_CD, IVPC.PY_BUYER_CD, IVPC.PY_DEPT_CD, #{ses.langCd}) AS PY_DEPT_NM ,GETBUYERDEPTNAME(IVPC.GATE_CD, IVPC.PY_BUYER_CD, IVPC.PY_DEPT_CD, #{ses.langCd}) AS PY_BUYER_DEPT_NM ,(IVHD.INV_DATE, 'YYYY-MM-DD') AS INV_DATE , IVAP.AP_REQ_SUBJECT ,(IVAP.AP_REQ_DATE, 'YYYY-MM-DD') AS AP_REQ_DATE ,(IVAP.BILL_DATE, 'YYYY-MM-DD') AS BILL_DATE , IVAP.GUAR_TYPE , IVAP.GUAR_PERCENT , IVAP.GUAR_TYPE2 , IVAP.GUARANTEER , IVAP.GUAR_QT , IVAP.GUAR_AMT , IVAP.BOND_BEGN_DATE , IVAP.BOND_FNSH_DATE , IVAP.GUAR_NUM , IVAP.GUAR_ATT_FILE_NUM , IVAP.GUAR_RMK , IVAP.PAY_BANK ,GETCODENAME(IVAP.GATE_CD, 'M017', IVAP.PAY_BANK, #{ses.langCd}) AS PAY_BANK_NM ,IVAP.PAY_ACCOUNT_NUM AS PAY_ACCOUNT_NUM , IVAP.PAY_ACC_NM , IVAP.PAY_ATT_FILE_NUM ,(CASE WHEN GETFILECOUNT(IVAP.GATE_CD, IVAP.PAY_ATT_FILE_NUM) = 0 THEN NULL ELSE GETFILECOUNT(IVAP.GATE_CD, IVAP.PAY_ATT_FILE_NUM) END) AS PAY_ATT_FILE_CNT , IVAP.INSU_STATUS , IVAP.BILL_ATT_FILE_NUM ,(CASE WHEN GETFILECOUNT(IVAP.GATE_CD, IVAP.BILL_ATT_FILE_NUM) = 0 THEN NULL ELSE GETFILECOUNT(IVAP.GATE_CD, IVAP.BILL_ATT_FILE_NUM) END) AS BILL_ATT_FILE_CNT , IVHD.PIC_USER_ID ,IVHD.PIC_USER_NM AS PIC_USER_NM , POHD.PAY_TYPE , IVPC.AP_USER_ID AS PAY_USER_ID ,GETUSERNAME(IVHD.GATE_CD, IVPC.AP_USER_ID, #{ses.langCd}) AS PAY_USER_NM , CASE WHEN IVAP.AP_USER_ID IS NULL THEN IVPC.AP_USER_ID ELSE IVAP.AP_USER_ID END AS AP_USER_ID ,GETUSERNAME(IVAP.GATE_CD, CASE WHEN IVAP.AP_USER_ID IS NULL THEN IVPC.AP_USER_ID ELSE IVAP.AP_USER_ID END, #{ses.langCd}) AS AP_USER_NM , CASE WHEN IVAP.PY_AP_REQ_DATE IS NULL THEN (IVPC.AP_REQ_DATE, 'YYYY-MM-DD') ELSE (IVAP.PY_AP_REQ_DATE, 'YYYY-MM-DD') END AS PY_AP_REQ_DATE , CASE WHEN IVAP.ACC_HNG_CD IS NULL THEN IVPC.ACC_HNG_CD ELSE IVAP.ACC_HNG_CD END AS ACC_HNG_CD , CASE WHEN IVAP.ACC_MOK_CD IS NULL THEN IVPC.ACC_MOK_CD ELSE IVAP.ACC_MOK_CD END AS ACC_MOK_CD , CASE WHEN IVAP.ACC_DET_CD IS NULL THEN IVPC.ACC_DET_CD ELSE IVAP.ACC_DET_CD END AS ACC_DET_CD , CASE WHEN IVAP.ACC_GWAN_CD IS NULL THEN IVPC.ACC_GWAN_CD ELSE IVAP.ACC_GWAN_CD END AS ACC_GWAN_CD , IVAP.ACC_NUM_YEAR , IVAP.ACC_NUM_TEXT , IVAP.APP_DOC_NUM , IVAP.APP_DOC_CNT , IVAP.APP_DOC_SIGN_STATUS , IVAP.SIGN_STATUS AS PROGRESS_CD , (SELECT IRS_NO FROM STOCVNGL WHERE GATE_CD = '100' AND DEL_FLAG = '0' AND VENDOR_CD = IVHD.VENDOR_CD) AS IRS_NO , (SELECT ATT_FILE_NUM FROM STOCATTS WHERE VENDOR_CD = IVHD.VENDOR_CD AND BUYER_CD = #{ses.manageCd} AND GATE_CD = #{ses.gateCd} AND DEL_FLAG = '0' AND TMPL_SQ = '1') AS ATTS_ATT_FILE_NUM , (SELECT CASE WHEN GETFILECOUNT(ATTS.GATE_CD, ATTS.ATT_FILE_NUM) = 0 THEN NULL ELSE GETFILECOUNT(ATTS.GATE_CD, ATTS.ATT_FILE_NUM) END AS ATTS_ATT_FILE_NUM_CNT FROM STOCATTS ATTS WHERE ATTS.VENDOR_CD = IVHD.VENDOR_CD AND ATTS.TMPL_SQ = '1' AND ATTS.BUYER_CD = #{ses.manageCd} AND ATTS.GATE_CD = #{ses.gateCd} AND ATTS.DEL_FLAG = '0') AS ATTS_ATT_FILE_NUM_CNT , IVAP.PDF_ATT_FILE_NUM FROM STOCIVAP IVAP JOIN STOCIVGH IVGH ON (IVGH.GATE_CD = IVAP.GATE_CD AND IVGH.BUYER_CD = IVAP.BUYER_CD AND IVGH.INV_NUM = IVAP.INV_NUM AND IVGH.DEL_FLAG = '0') JOIN STOCIVHD IVHD ON (IVHD.GATE_CD = IVGH.GATE_CD AND IVHD.BUYER_CD = IVGH.BUYER_CD AND IVHD.INV_NUM = IVGH.INV_NUM AND IVHD.DEL_FLAG = '0') JOIN STOCPOHD POHD ON (POHD.GATE_CD = IVHD.GATE_CD AND POHD.BUYER_CD = IVHD.BUYER_CD AND POHD.PO_NUM = IVGH.PO_NUM AND POHD.DEL_FLAG = '0') JOIN STOCPOPY POPY ON (POPY.GATE_CD = IVAP.GATE_CD AND POPY.BUYER_CD = IVAP.BUYER_CD AND POPY.PO_NUM = IVAP.PO_NUM AND POPY.PAY_CNT = IVAP.PAY_CNT AND POPY.DEL_FLAG = '0') LEFT JOIN STOCIVPC IVPC ON (IVPC.GATE_CD = POPY.GATE_CD AND IVPC.BUYER_CD = POPY.BUYER_CD AND IVPC.INV_NUM = IVHD.INV_NUM AND IVPC.PO_NUM = POPY.PO_NUM AND IVPC.DEPT_CD = POPY.DEPT_CD AND IVPC.PAY_CNT = POPY.PAY_CNT AND IVPC.PY_BUYER_CD = IVAP.PY_BUYER_CD AND IVPC.PY_DEPT_CD = IVAP.PY_DEPT_CD AND IVPC.DEL_FLAG = '0') WHERE IVAP.GATE_CD = #{ses.gateCd} AND IVAP.BUYER_CD = #{BUYER_CD}
AND IVAP.AP_NUM = #{AP_NUM}
AND IVAP.APP_DOC_NUM = #{APP_DOC_NUM}
AND IVAP.DEL_FLAG = '0'

